query:
SELECT `key`, `value` FROM workflow_settings 
WHERE `key` IN (
  'production_loop_enabled','production_mode','production_interval_minutes',
  'max_daily_articles','max_batch_high','max_batch_medium',
  'min_score_to_publish','score_high_threshold','score_medium_threshold',
  'pool_min_size','brand_genre','candidate_expiry_hours',
  'expiry_breaking_hours','expiry_trending_hours','expiry_evergreen_hours',
  'score_decay_hours'
)
ORDER BY `key`;

SELECT articlePotential, COUNT(*) as cnt 
FROM selector_candidates 
WHERE status = 'pending'
GROUP BY articlePotential;

SELECT COUNT(*) as total_pending FROM selector_candidates WHERE status = 'pending';
SELECT COUNT(*) as total_articles FROM articles;
SELECT COUNT(*) as published_today FROM articles 
WHERE createdAt >= CURDATE() AND status IN ('published','pending_approval');

